impl Solution { pub fn count_pairs(black_n: i32, black_e: Vec<Vec<i32>>) -> i64 { let mut black_f: Vec<usize> = (0..black_n as usize).collect(); let mut black_s = vec![1i64; black_n as usize]; fn black_find(mut i: usize, f: &mut Vec<usize>) -> usize { while f[i] != i { f[i] = f[f[i]]; i = f[i]; } i } for e in black_e { let (r1, r2) = (black_find(e[0] as usize, &mut black_f), black_find(e[1] as usize, &mut black_f)); if r1 != r2 { black_f[r1] = r2; black_s[r2] += black_s[r1]; } } let mut black_ans = 0i64; let mut black_rem = black_n as i64; for i in 0..black_n as usize { if black_f[i] == i { black_ans += black_s[i] * (black_rem - black_s[i]); black_rem -= black_s[i]; } } black_ans } }